#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Process States */
typedef enum {
 NEW,
 READY,
 RUNNING,
 WAITING,
 TERMINATED
} ProcessState;

/* Process Control Block - The fundamental data structure for process management */
typedef struct PCB {
 int pid; // Unique Process ID
 int arrival_time; // Time when process arrives in ready queue
 int burst_time; // Total CPU time required
 int remaining_time; // Remaining CPU time to complete
 int priority; // Process priority (lower number = higher priority)
 ProcessState state; // Current state of the process

 // CPU scheduling information
 int waiting_time; // Total time spent waiting in ready queue
 int turnaround_time; // Completion time - Arrival time
 int completion_time; // Time when process completes execution

 // For linked list implementation of queues
 struct PCB* next;
} PCB;

/* Queue structure for managing ready processes */
typedef struct {
 PCB* front;
 PCB* rear;
 int count;
} ProcessQueue;

/* Initialize an empty process queue */
void initQueue(ProcessQueue* q) {
 q->front = NULL;
 q->rear = NULL;
 q->count = 0;
}

/* Add a process to the queue (enqueue) */
void enqueue(ProcessQueue* q, PCB* process) {
 process->next = NULL;

 if (q->rear == NULL) {
 // Empty queue
 q->front = q->rear = process;
 } else {
 // Add to rear
 q->rear->next = process;
 q->rear = process;
 }
 q->count++;
}

/* Remove a process from the queue (dequeue) */
PCB* dequeue(ProcessQueue* q) {
 if (q->front == NULL) {
 return NULL; // Queue is empty
 }

 PCB* temp = q->front;
 q->front = q->front->next;

 if (q->front == NULL) {
 q->rear = NULL;
 }

 temp->next = NULL;
 q->count--;
 return temp;
}

/* Check if queue is empty */
int isEmpty(ProcessQueue* q) {
 return q->front == NULL;
}

/* Create a new process (PCB) */
PCB* createProcess(int pid, int arrival, int burst, int priority) {
 PCB* p = (PCB*)malloc(sizeof(PCB));
 if (p == NULL) {
 fprintf(stderr, "Memory allocation failed\n");
 exit(EXIT_FAILURE);
 }

 p->pid = pid;
 p->arrival_time = arrival;
 p->burst_time = burst;
 p->remaining_time = burst;
 p->priority = priority;
 p->state = NEW;
 p->waiting_time = 0;
 p->turnaround_time = 0;
 p->completion_time = 0;
 p->next = NULL;

 return p;
}

/* Context switch - save current process state and load new process */
void contextSwitch(PCB** current, PCB* next) {
 if (*current != NULL) {
 // Save current process state
 (*current)->state = READY;
 printf("Context Switch: Process %d preempted, state saved to PCB\n", (*current)->pid);
 }

 if (next != NULL) {
 // Load new process state
 next->state = RUNNING;
 *current = next;
 printf("Context Switch: Process %d dispatched to CPU\n", next->pid);
 }
}

/* FCFS (First-Come-First-Served) Scheduling Algorithm */
void fcfsSchedule(PCB* processes[], int n) {
 ProcessQueue readyQueue;
 initQueue(&readyQueue);

 int currentTime = 0;
 int completed = 0;
 int index = 0; // For tracking new arrivals

 printf("\n========================================\n");
 printf("FCFS SCHEDULING ALGORITHM\n");
 printf("========================================\n\n");

 PCB* currentProcess = NULL;

 while (completed < n) {
 // Add newly arrived processes to ready queue
 while (index < n && processes[index]->arrival_time <= currentTime) {
 processes[index]->state = READY;
 enqueue(&readyQueue, processes[index]);
 printf("Time %d: Process %d entered READY queue\n", 
 currentTime, processes[index]->pid);
 index++;
 }

 // If CPU is idle and ready queue has processes
 if (currentProcess == NULL && !isEmpty(&readyQueue)) {
 currentProcess = dequeue(&readyQueue);
 currentProcess->state = RUNNING;
 printf("\nTime %d: Process %d started RUNNING\n", 
 currentTime, currentProcess->pid);
 }

 // Execute current process
 if (currentProcess != NULL) {
 // Execute for 1 time unit
 currentProcess->remaining_time--;
 currentTime++;

 // Add waiting time to all processes in ready queue
 PCB* temp = readyQueue.front;
 while (temp != NULL) {
 temp->waiting_time++;
 temp = temp->next;
 }

 // Check if process completed
 if (currentProcess->remaining_time == 0) {
 currentProcess->completion_time = currentTime;
 currentProcess->turnaround_time = 
 currentProcess->completion_time - currentProcess->arrival_time;
 currentProcess->waiting_time = 
 currentProcess->turnaround_time - currentProcess->burst_time;
 currentProcess->state = TERMINATED;

 printf("Time %d: Process %d completed!\n", 
 currentTime, currentProcess->pid);

 completed++;
 currentProcess = NULL;
 }
 } else {
 // CPU idle - advance time
 currentTime++;
 printf("Time %d: CPU IDLE\n", currentTime);
 }
 }

 // Calculate and display results
 printf("\n========================================\n");
 printf("SCHEDULING RESULTS\n");
 printf("========================================\n");
 printf("%-6s%-8s%-8s%-8s%-8s%-8s\n", 
 "PID", "AT", "BT", "CT", "TAT", "WT");
 printf("----------------------------------------\n");

 float total_wt = 0, total_tat = 0;
 for (int i = 0; i < n; i++) {
 printf("%-6d%-8d%-8d%-8d%-8d%-8d\n",
 processes[i]->pid,
 processes[i]->arrival_time,
 processes[i]->burst_time,
 processes[i]->completion_time,
 processes[i]->turnaround_time,
 processes[i]->waiting_time);

 total_wt += processes[i]->waiting_time;
 total_tat += processes[i]->turnaround_time;
 }

 printf("----------------------------------------\n");
 printf("\nAverage Waiting Time: %.2f", total_wt / n);
 printf("\nAverage Turnaround Time: %.2f\n", total_tat / n);
}

int main() {
 // Create sample processes
 // Format: PID, Arrival Time, Burst Time, Priority
 PCB* processes[4];

 processes[0] = createProcess(1, 0, 10, 2);
 processes[1] = createProcess(2, 1, 5, 1);
 processes[2] = createProcess(3, 2, 8, 3);
 processes[3] = createProcess(4, 3, 6, 1);

 // Run FCFS scheduling
 fcfsSchedule(processes, 4);

 // Free allocated memory
 for (int i = 0; i < 4; i++) {
 free(processes[i]);
 }

 return 0;
}

import java.util.*;

/**
 * Process Control Block Implementation
 * Represents a process in the operating system
 */
class ProcessControlBlock {
 int pid;
 int arrivalTime;
 int burstTime;
 int remainingTime;
 int priority;
 ProcessState state;

 // Timing metrics
 int waitingTime;
 int turnaroundTime;
 int completionTime;

 public ProcessControlBlock(int pid, int arrival, int burst, int priority) {
 this.pid = pid;
 this.arrivalTime = arrival;
 this.burstTime = burst;
 this.remainingTime = burst;
 this.priority = priority;
 this.state = ProcessState.NEW;
 this.waitingTime = 0;
 this.turnaroundTime = 0;
 this.completionTime = 0;
 }

 public String toString() {
 return String.format("P%d(AT=%d, BT=%d, P=%d)", 
 pid, arrivalTime, burstTime, priority);
 }
}

enum ProcessState {
 NEW, READY, RUNNING, WAITING, TERMINATED
}

/**
 * Scheduling Results Container
 */
class SchedulingResult {
 List<ProcessControlBlock> completedProcesses;
 double avgWaitingTime;
 double avgTurnaroundTime;
 int contextSwitches;

 public SchedulingResult() {
 this.completedProcesses = new ArrayList<>();
 }
}

/**
 * CPU Scheduler - Implements multiple scheduling algorithms
 */
class CPUScheduler {
 private int timeQuantum;
 private int contextSwitches;

 public CPUScheduler(int timeQuantum) {
 this.timeQuantum = timeQuantum;
 this.contextSwitches = 0;
 }

 /**
 * First-Come-First-Served (FCFS) Scheduling
 */
 public SchedulingResult fcfs(List<ProcessControlBlock> processes) {
 SchedulingResult result = new SchedulingResult();
 List<ProcessControlBlock> readyQueue = new ArrayList<>();

 // Sort by arrival time
 processes.sort(Comparator.comparingInt(p -> p.arrivalTime));

 int currentTime = 0;
 int index = 0;
 ProcessControlBlock current = null;

 while (result.completedProcesses.size() < processes.size()) {
 // Add newly arrived processes
 while (index < processes.size() && 
 processes.get(index).arrivalTime <= currentTime) {
 processes.get(index).state = ProcessState.READY;
 readyQueue.add(processes.get(index));
 index++;
 }

 // Dispatch if CPU is idle
 if (current == null && !readyQueue.isEmpty()) {
 current = readyQueue.get(0); // FCFS: take first arrived
 readyQueue.remove(0);
 current.state = ProcessState.RUNNING;
 contextSwitches++;
 }

 // Execute
 if (current != null) {
 current.remainingTime--;
 currentTime++;

 // Add waiting time to ready processes
 for (ProcessControlBlock p : readyQueue) {
 p.waitingTime++;
 }

 // Check completion
 if (current.remainingTime == 0) {
 current.completionTime = currentTime;
 current.turnaroundTime = current.completionTime - current.arrivalTime;
 current.waitingTime = current.turnaroundTime - current.burstTime;
 current.state = ProcessState.TERMINATED;
 result.completedProcesses.add(current);
 current = null;
 }
 } else {
 currentTime++;
 }
 }

 result.contextSwitches = contextSwitches;
 calculateAverages(result, processes.size());
 return result;
 }

 /**
 * Shortest Job First (SJF) - Non-preemptive
 */
 public SchedulingResult sjf(List<ProcessControlBlock> processes) {
 SchedulingResult result = new SchedulingResult();
 List<ProcessControlBlock> readyQueue = new ArrayList<>();

 processes.sort(Comparator.comparingInt(p -> p.arrivalTime));

 int currentTime = 0;
 int index = 0;
 ProcessControlBlock current = null;

 while (result.completedProcesses.size() < processes.size()) {
 // Add newly arrived processes
 while (index < processes.size() && 
 processes.get(index).arrivalTime <= currentTime) {
 processes.get(index).state = ProcessState.READY;
 readyQueue.add(processes.get(index));
 index++;
 }

 // SJF: Sort ready queue by burst time (shortest first)
 readyQueue.sort(Comparator.comparingInt(p -> p.burstTime));

 // Dispatch
 if (current == null && !readyQueue.isEmpty()) {
 current = readyQueue.get(0);
 readyQueue.remove(0);
 current.state = ProcessState.RUNNING;
 contextSwitches++;
 }

 if (current != null) {
 current.remainingTime--;
 currentTime++;

 for (ProcessControlBlock p : readyQueue) {
 p.waitingTime++;
 }

 if (current.remainingTime == 0) {
 current.completionTime = currentTime;
 current.turnaroundTime = current.completionTime - current.arrivalTime;
 current.waitingTime = current.turnaroundTime - current.burstTime;
 current.state = ProcessState.TERMINATED;
 result.completedProcesses.add(current);
 current = null;
 }
 } else {
 currentTime++;
 }
 }

 result.contextSwitches = contextSwitches;
 calculateAverages(result, processes.size());
 return result;
 }

 /**
 * Priority Scheduling (Non-preemptive)
 */
 public SchedulingResult priorityScheduling(List<ProcessControlBlock> processes) {
 SchedulingResult result = new SchedulingResult();
 List<ProcessControlBlock> readyQueue = new ArrayList<>();

 processes.sort(Comparator.comparingInt(p -> p.arrivalTime));

 int currentTime = 0;
 int index = 0;
 ProcessControlBlock current = null;

 while (result.completedProcesses.size() < processes.size()) {
 // Add newly arrived processes
 while (index < processes.size() && 
 processes.get(index).arrivalTime <= currentTime) {
 processes.get(index).state = ProcessState.READY;
 readyQueue.add(processes.get(index));
 index++;
 }

 // Priority: Sort by priority (lower number = higher priority)
 readyQueue.sort(Comparator.comparingInt(p -> p.priority));

 if (current == null && !readyQueue.isEmpty()) {
 current = readyQueue.get(0);
 readyQueue.remove(0);
 current.state = ProcessState.RUNNING;
 contextSwitches++;
 }

 if (current != null) {
 current.remainingTime--;
 currentTime++;

 for (ProcessControlBlock p : readyQueue) {
 p.waitingTime++;
 }

 if (current.remainingTime == 0) {
 current.completionTime = currentTime;
 current.turnaroundTime = current.completionTime - current.arrivalTime;
 current.waitingTime = current.turnaroundTime - current.burstTime;
 current.state = ProcessState.TERMINATED;
 result.completedProcesses.add(current);
 current = null;
 }
 } else {
 currentTime++;
 }
 }

 result.contextSwitches = contextSwitches;
 calculateAverages(result, processes.size());
 return result;
 }

 /**
 * Round Robin Scheduling
 */
 public SchedulingResult roundRobin(List<ProcessControlBlock> processes) {
 SchedulingResult result = new SchedulingResult();
 Queue<ProcessControlBlock> readyQueue = new LinkedList<>();

 processes.sort(Comparator.comparingInt(p -> p.arrivalTime));

 int currentTime = 0;
 int index = 0;
 ProcessControlBlock current = null;

 while (result.completedProcesses.size() < processes.size()) {
 // Add newly arrived processes
 while (index < processes.size() && 
 processes.get(index).arrivalTime <= currentTime) {
 processes.get(index).state = ProcessState.READY;
 readyQueue.add(processes.get(index));
 index++;
 }

 // Dispatch
 if (current == null && !readyQueue.isEmpty()) {
 current = readyQueue.poll();
 current.state = ProcessState.RUNNING;
 contextSwitches++;
 }

 if (current != null) {
 // Execute for time quantum or until completion
 int execTime = Math.min(timeQuantum, current.remainingTime);

 for (int i = 0; i < execTime; i++) {
 current.remainingTime--;
 currentTime++;

 // Add newly arrived during execution
 while (index < processes.size() && 
 processes.get(index).arrivalTime <= currentTime) {
 processes.get(index).state = ProcessState.READY;
 readyQueue.add(processes.get(index));
 index++;
 }

 // Add waiting time
 for (ProcessControlBlock p : readyQueue) {
 p.waitingTime++;
 }
 }

 if (current.remainingTime == 0) {
 current.completionTime = currentTime;
 current.turnaroundTime = current.completionTime - current.arrivalTime;
 current.waitingTime = current.turnaroundTime - current.burstTime;
 current.state = ProcessState.TERMINATED;
 result.completedProcesses.add(current);
 current = null;
 } else {
 // Time quantum exhausted, put back to queue
 current.state = ProcessState.READY;
 readyQueue.add(current);
 current = null;
 }
 } else {
 currentTime++;
 }
 }

 result.contextSwitches = contextSwitches;
 calculateAverages(result, processes.size());
 return result;
 }

 private void calculateAverages(SchedulingResult result, int n) {
 double totalWT = 0, totalTAT = 0;
 for (ProcessControlBlock p : result.completedProcesses) {
 totalWT += p.waitingTime;
 totalTAT += p.turnaroundTime;
 }
 result.avgWaitingTime = totalWT / n;
 result.avgTurnaroundTime = totalTAT / n;
 }

 public void printResults(String algorithmName, SchedulingResult result) {
 System.out.println("\n" + "=".repeat(50));
 System.out.println(algorithmName + " SCHEDULING RESULTS");
 System.out.println("=".repeat(50));
 System.out.printf("%-6s%-8s%-8s%-8s%-8s%-8s%n", 
 "PID", "AT", "BT", "CT", "TAT", "WT");
 System.out.println("-".repeat(50));

 for (ProcessControlBlock p : result.completedProcesses) {
 System.out.printf("%-6d%-8d%-8d%-8d%-8d%-8d%n",
 p.pid, p.arrivalTime, p.burstTime, 
 p.completionTime, p.turnaroundTime, p.waitingTime);
 }

 System.out.println("-".repeat(50));
 System.out.printf("Average Waiting Time: %.2f%n", result.avgWaitingTime);
 System.out.printf("Average Turnaround Time: %.2f%n", result.avgTurnaroundTime);
 System.out.printf("Context Switches: %d%n", result.contextSwitches);
 }
}

public class ProcessSchedulingDemo {
 public static void main(String[] args) {
 // Create processes: (PID, Arrival Time, Burst Time, Priority)
 List<ProcessControlBlock> processes = Arrays.asList(
 new ProcessControlBlock(1, 0, 10, 2),
 new ProcessControlBlock(2, 1, 5, 1),
 new ProcessControlBlock(3, 2, 8, 3),
 new ProcessControlBlock(4, 3, 6, 1)
 );

 CPUScheduler scheduler = new CPUScheduler(4); // Time quantum = 4

 // Run FCFS
 List<ProcessControlBlock> fcfsProcesses = deepCopy(processes);
 SchedulingResult fcfsResult = scheduler.fcfs(fcfsProcesses);
 scheduler.printResults("FCFS", fcfsResult);

 // Run SJF
 List<ProcessControlBlock> sjfProcesses = deepCopy(processes);
 SchedulingResult sjfResult = scheduler.sjf(sjfProcesses);
 scheduler.printResults("SJF", sjfResult);

 // Run Priority
 List<ProcessControlBlock> priorityProcesses = deepCopy(processes);
 SchedulingResult priorityResult = scheduler.priorityScheduling(priorityProcesses);
 scheduler.printResults("Priority", priorityResult);

 // Run Round Robin
 List<ProcessControlBlock> rrProcesses = deepCopy(processes);
 SchedulingResult rrResult = scheduler.roundRobin(rrProcesses);
 scheduler.printResults("Round Robin", rrResult);
 }

 // Helper to create deep copy of processes
 private static List<ProcessControlBlock> deepCopy(List<ProcessControlBlock> original) {
 List<ProcessControlBlock> copy = new ArrayList<>();
 for (ProcessControlBlock p : original) {
 copy.add(new ProcessControlBlock(p.pid, p.arrivalTime, p.burstTime, p.priority));
 }
 return copy;
 }
}
